// Solution
function calculateRowHeights(gridLayout) {
  var rows = gridLayout.split(';');
  var rowHeights = {};
  for (var i = 0; i < rows.length; i++) {
    var row = rows[i].trim().split('grid-template-columns:')[1].split('grid-template-rows:')[0].split(' '); 
    if (row[0].includes('auto')) {
      var maxHeight = 0;
      for (var j = 1; j < row.length; j++) {
        if (row[j].includes('px')) {
          maxHeight = Math.max(maxHeight, parseInt(row[j].split('px')[0]));
        }
      }
      rowHeights[i] = maxHeight;
    } else {
      rowHeights[i] = parseInt(row[0].split('px')[0]);
    }
  }
  return rowHeights;
}

