class Solution:
  def calculate_row_heights(self, grid_layout: str) -> dict:
    rows = grid_layout.split(';')
    rowHeights = {}
    for i in range(len(rows)):
      row = rows[i].strip().split('grid-template-columns:')[1].split('grid-template-rows:')[0].split(' ') 
      if 'auto' in row[0]:
        maxHeight = 0
        for j in range(1, len(row)):
          if 'px' in row[j]:
            maxHeight = max(maxHeight, int(row[j].split('px')[0]))
        rowHeights[i] = maxHeight
      else:
        rowHeights[i] = int(row[0].split('px')[0])
    return rowHeights;
